text:
{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "confirmed_decisions": [
      {
        "내용": "공개 릴리스 목표 시각은 스모크 테스트 통과를 조건으로 금요일 15:00 KST로 확정.",
        "조건": "스모크 테스트 통과 시"
      },
      {
        "내용": "packageName 불일치 발생 시 우선 패키지 설정(계약) 점검 후, 계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 검토."
      }
    ],
    "rejected_proposals": [
      {
        "제안": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "결론": "반려"
      }
    ],
    "internal_stretch_goals": [
      {
        "내용": "수요일 릴리스 제안은 내부 스트레치 목표로만 유지",
        "확정여부": "비확정(대외 목표 아님)"
      }
    ],
    "non_decisions": [
      {
        "내용": "README 설치 단계는 가능하면 목요일 검토 필요 의견이 있었으나 담당자 미지정"
      },
      {
        "내용": "수요일 내부 스트레치 목표를 릴리스 노트에 명시할지 미결정"
      }
    ],
    "risks": [
      {
        "내용": "잘못된 tarball 경로로 릴리스 지연 가능"
      },
      {
        "내용": "README 설치 단계가 최신이 아니면 릴리스 노트가 사용자 오도 가능"
      }
    ],
    "open_questions": [
      {
        "질문": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "질문": "릴리스 노트에 내부 수요일 스트레치 목표를 포함해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 점검",
      "due": "미정",
      "status": "대기(선행조건: 스모크 결과 공유)",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토(가능하면 목요일)",
      "due": "목요일(권고, 확정 아님)",
      "status": "담당자 지정 필요",
      "source_certainty": "tentative"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun 스모크 테스트 결과 통과/실패 여부 확인",
      "Doyun 실패 트리아지 노트 작성 완료 여부 확인",
      "Hara의 tarball 경로 점검 결과 확인",
      "README 설치 단계 검토 담당자 지정 여부 확인",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 수요일 내부 스트레치 목표 기재 여부 결정"
    ],
    "do_not_invent": [
      "고객명/외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "미지정 담당자/마감의 임의 확정"
    ]
  },
  "non_invention_rules": {
    "policy": "회의 원문에 명시된 사실만 사용하며, 추정·보간·외삽 금지",
    "explicit_non_facts": [
      "고객명 없음",
      "예산 언급 없음",
      "보안 사고 없음",
      "프로덕션 장애 없음",
      "법무 승인 요건 언급 없음"
    ],
    "assumptions": [
      "시간 표기는 원문의 KST 기준을 유지",
      "‘금요일/목요일/수요일’은 원문 상대 표현 그대로 보존(달력 날짜로 확정하지 않음)"
    ]
  }
}
